import React, { useState, useEffect } from 'react';
import { AdminService } from '../../../services/api';

export const AdminTaxonomy = () => {
  const [data, setData] = useState<any>({ themes: [], tags: [] });

  useEffect(() => {
    AdminService.getAllTaxonomy().then((res: any) => {
      // Ensure we always have an array even if backend returns null
      setData(res.data || { themes: [], tags: [] });
    });
  }, []);

  return (
    <div className="p-8 text-white">
      <h1 className="text-3xl font-bold mb-6 italic">Taxonomy Control</h1>
      <div className="grid grid-cols-2 gap-8">
        <section className="bg-white/5 p-6 rounded-2xl border border-white/10">
          <h2 className="text-primary font-bold mb-4">Themes</h2>
          {data.themes?.length > 0 ? (
            data.themes.map((t: any) => <div key={t._id} className="p-2 border-b border-white/5">{t.name}</div>)
          ) : <p className="text-gray-500">No themes found.</p>}
        </section>
        
        <section className="bg-white/5 p-6 rounded-2xl border border-white/10">
          <h2 className="text-primary font-bold mb-4">Tags</h2>
          {data.tags?.length > 0 ? (
            data.tags.map((t: any) => <div key={t._id} className="p-2 border-b border-white/5">{t.name}</div>)
          ) : <p className="text-gray-500">No tags found.</p>}
        </section>
      </div>
    </div>
  );
};
